external_knowledge:
- Top earning urban centers: metropolitan areas with the highest average annual mean wages;
- Average yearly pay: the average annual mean wage of each metropolitan area;
- Top five in each region: the top 5 metropolitan areas for each state based on their average annual mean wages.

- "bustling cities" refers to metropolitan areas;
- "particularly lengthy names" means state names with more than 10 characters;
- "significant number of residents" implies a population exceeding 1,000,000.

sql:
SELECT AVG(population) AS average_population
FROM metro_area
WHERE state_id = (SELECT state_id FROM state WHERE state_name = 'California');

SELECT state_id, AVG(population) AS average_population, AVG(area_square_miles) AS average_area
FROM metro_area
GROUP BY state_id;

SELECT metro_area_name, AVG(employment_per_thousand_jobs) AS average_employment_per_thousand_jobs
FROM employment_data
GROUP BY metro_area_name;

SELECT metro_area_name
FROM metro_area
WHERE population = (SELECT MAX(population) FROM metro_area);

SELECT username, role_name
FROM user
JOIN role ON user.role_id = role.role_id;

SELECT metro_area_id, metro_area_name, (population / area_square_miles) AS population_density
FROM metro_area
ORDER BY population_density DESC;

SELECT metro_area_id, FLOOR(AVG(employment)) AS Average_Employment
FROM employment_data
GROUP BY metro_area_id;
